var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"앗, 저기 있어요!","JPN":"あっ！　あそこにいます！","ENG":"Oh! They're over there!","TWN":"喔，在那！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"이번 임무는 철저히 변수를 제외하며 준비했다.","JPN":"今回の任務は徹底的に不確定要素の排除を行ってきた。","ENG":"We've prepared this operation meticulously by excluding all variables.","TWN":"這次任務我們徹底排除了所有變數。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"다방면으로 분석하고, 모든 경우의 수를 계산했어.","JPN":"あらゆる角度から分析し、あらゆる可能性を想定した。","ENG":"We analyzed it in many ways, and even calculated all the possible cases.","TWN":"全方面地分析了所有情況。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"가장 성공률이 높은 경로에 함선을 배치하고 적의 후방을 노렸다.","JPN":"最も成功率の高いルートに艦船を配備し、敵の後方を狙ったはずだ。","ENG":"We deployed ships where the success rates were the highest and aimed at the enemy's rear.","TWN":"甚至將艦船部署在成功率最高的路線上，瞄準了敵人的後方。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"하지만 어째서 이런 일이 발생한 거지?","JPN":"なのに、どうしてこんなことになってしまった？","ENG":"But how did this happen?","TWN":"但為什麼會發生這種事？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"분명 테라브레인의 예측에는 문제가 없었다.","JPN":"テラブレインの予測に問題点はなかった。","ENG":"There definitely weren't any issues with Terrabrain's predictions.","TWN":"顯然特拉大腦的預測沒有問題。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"우리도 그 예측을 검토할 시간은 충분했어.","JPN":"我々にも、予測内容を検討する時間が十分にあった。","ENG":"There was plenty of time for us to review the predictions.","TWN":"我們也有足夠的時間來評估那個預測。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"그렇다면 무언가 개입해 변수를 만든 것이 틀림없다.","JPN":"だとすると、何かの介入によって想定外の状況が発生したと考えるしかない。","ENG":"Which leaves us with that someone must have intervened to create a variable.","TWN":"那麼，肯定是有什麼東西介入，製造了變數。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"도대체 누가…….","JPN":"いったい誰が……","ENG":"But who...?","TWN":"到底是誰……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>저 자는 마귀 우두머리의 힘을 빌리지 않고서는 마귀들을 쫓아내지 못한다</color>","JPN":"<color=#ff3636>あの者は魔物の長の手を借りずして、魔物を追い払うことができない。</color>","ENG":"<color=#ff3636>He cannot drive out the demons without borrowing the power of the demon leader.</color>","TWN":"<color=#ff3636>想要驅逐魔鬼，必向魔鬼之主發出乞求。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>어리석은 자들은 세상의 흐름을 보지 못하느니.</color>","JPN":"<color=#ff3636>愚か者たちは、世界の姿を正しく見ることができない。</color>","ENG":"<color=#ff3636>The foolish do not see the flow of the world.</color>","TWN":"<color=#ff3636>愚蠢之人看不見世界的流向。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>우리는 모두 그분의 겹눈이 되어 관조자의 눈으로 세상을 바라본다.</color>","JPN":"<color=#ff3636>我々は皆、あのお方の複眼となり、観照者として世界を眺めるのだ。</color>","ENG":"<color=#ff3636>We all become our Master's compound eyes and see the world with the eyes of an observer.</color>","TWN":"<color=#ff3636>我們成為祂的複眼，用觀照者的眼睛洞察世界。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>그것이 위대한 분의 뜻대로 세상을 정화하는 길.</color>\xA0","JPN":"<color=#ff3636>それが、あのお方のお心のままに、世界を浄化させる術。</color>\xA0","ENG":"<color=#ff3636>For that is the path to purify the world according to the great one.</color>\xA0","TWN":"<color=#ff3636>那是按照偉大之人的意願淨化世界的道路。</color>\xA0"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"현재 통신 장비를 포함한 모든 전자 장비는 정보 오염이 진행됐을 가능성이 높다.","JPN":"現在、通信設備などのあらゆる電子系の装備は、情報汚染に侵された可能性が高い。","ENG":"It is highly likely that all our electronics, including our comms, have been infected with the data corruption.","TWN":"目前包括通訊在內的所有電子設備都有可能已經遭受資訊污染。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"모두 주의하도록.","JPN":"全員、十分気を付けるように。","ENG":"Everyone, be cautious.","TWN":"請大家注意。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L32_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"내가 모두를 죽인 거야. 내 안일함이…… 내 잘못된 판단 한 번으로 모두가……!","JPN":"私が殺してしまった。私の甘さが……私の間違った判断が……皆を……！","ENG":"I killed them all. My carelessness... Just one wrong call, and everyone...!","TWN":"是我害死了所有人。因為我的疏忽……因為我一次錯誤的判斷……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"작전을 위해 모든 가능성을 살펴봤잖아, 이건 연산을 뛰어넘는 존재의 개입이 있다는 거야.\xA0","JPN":"作戦にあたって、あらゆる可能性を考慮していたはずだ。これは演算でも捉えきれない存在からの介入があったとしか言いようがない。\xA0","ENG":"We looked into all the possible outcomes for this operation. This must mean that there was an intervention from an entity beyond the calculation.\xA0","TWN":"我們已經考慮了所有的可能性。這只能說明有超越我們計算的存在介入。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"아마 이 의식은 그런 존재를 불러오는 것일지도 모르지.","JPN":"おそらく、この儀式はその存在を呼び込むためのものかもな。","ENG":"Perhaps this ritual is to summon such a being.","TWN":"也許這個儀式就是為了召喚那個東西。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"여기서 주저앉아 있을 시간이 없다. 아디트야. 우린 나아가야 해.","JPN":"こんな場所でうなだれている暇はないぞ、アーディティヤ。俺たちは突き進まなければならない。","ENG":"There's no time to waste. Aditya. We must move forward.","TWN":"我們沒時間在這裡浪費，阿迪亞。我們必須前進。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"……젠장.","JPN":"……くそ。","ENG":"...Dammit.","TWN":"……可惡。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"우선 후발대로 오게 될지도 모를 아군에게 전달할 정보를 취합한다.","JPN":"では、ここに来るかもしれない支援部隊に伝えるための情報を整理する。","ENG":"First, let's gather information to pass on to allies who may arrive later.","TWN":"雖然不知道會不會有後援，但就先收集好需要傳達給他們的資訊吧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"먼저 의식이 시작된 순간, 의식의 중심으로부터 이면 세계화가 일어났다.","JPN":"まず、儀式が始まった瞬間、儀式の中心部から裏世界化が引き起こされた。","ENG":"When the ritual began, the Counterside Effect occurred from the center of the ritual.","TWN":"儀式開始的瞬間，從儀式的中心發生異界化。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"이면 세계화는 황폐해진 사막 도시로 변하며, 보고된 바가 없는 형태다.","JPN":"その詳細は、街を荒廃した砂漠都市へと変容するもので、かつて観測されたことのない特徴である。","ENG":"This kind of Counterside Effect changing the landscape into a devastated desert city has never been reported before.","TWN":"異界化就是變成荒蕪的沙漠城市，這是首次發現的內容。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L43_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"의식의 목적은…… 파악된 바가 없다.","JPN":"儀式の目的は……未だに把握できていない。","ENG":"The objective of the ritual is... still unknown.","TWN":"儀式的目的……待確。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"현재 피해 상황은…… 민간인을 대피시키려 차출한 몇을 빼곤 모두 전멸로 예상.","JPN":"現在の被害状況は……民間人の避難誘導を遂行していた人員を除き全滅と予想。","ENG":"The current damage of the situation is... that we expect all but the few who were sent out to evacuate the civilians to die.","TWN":"目前的受害情況是……除去派出疏散平民的幾人外，估計全部陣亡。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"또한 무전 및 전자 장비에서 정보 오염 현상이 발생하고 있다.","JPN":"また、無線および電子系の装備から情報汚染が発生している。","ENG":"Also, data corruption is occurring in our radio and electronic devices.","TWN":"此外，無線電和電子設備也有出現資訊污染現象。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"학회가 관여하고 있는 만큼, <color=#ffd34c>가아그셰블라</color>와 관련이 있다고 추정하지만 속단할 수 없다.\xA0","JPN":"学会が関与しているだけに、<color=#ffd34c>ガアグシェブラ</color>との関連性を疑っているが、まだ断定はできない。\xA0","ENG":"With the Society involved, we assume that this is linked to <color=#ffd34c>Gha'agsheblah</color>, but have not jumped to any conclusions.\xA0","TWN":"既然學會已經介入，我們推測可能與<color=#ffd34c>加格舍夫拉</color>有關，但無法作出定論。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"도시 전체에선 클리파 허수 에너지 밀도가 계속해서 상승하고 있다.","JPN":"都市全体からクリファ虚数エネルギーの密度がどんどん上昇している。","ENG":"Qlipha Imaginary Energy density is continually rising across the city.","TWN":"整個城市的逆卡巴拉虛數能量密度持續上升。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"아군 병력은 퇴각 중 모두 변이…… 된 것으로 추정…… 되며…… ","JPN":"味方の兵士たちは退却の途中、全員が変異……してしまったと……思われ…… ","ENG":"Ally forces are... assumed to have... mutated... while retreating...","TWN":"我方撤退兵力推測已……全部變異……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L49_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"젠장!","JPN":"くそ！","ENG":"Dammit!","TWN":"該死！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"아직 변이되지 않고 살아 있을지도 몰라.","JPN":"まだ変異せずに生きている者がいるかもしれない。","ENG":"Maybe some are still alive and have not mutated.","TWN":"可能還有人沒有變異，還活著。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"남은 인원들이라도 서둘러 이곳을 빠져나가야 한다.","JPN":"残りの人員だけでも、一刻でも早くここから離脱しなければならない。","ENG":"The remaining troops must leave quickly.","TWN":"剩下的人也要趕快離開這裡。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"다들 재정비를…….","JPN":"皆、再整備を……","ENG":"I need to–","TWN":"大家重新整頓……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"지진……?","JPN":"地震……？","ENG":"An earthquake...?","TWN":"地震……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"침식체 반응 확인! 땅속에서 올라오고 있습니다!","JPN":"侵食体の反応を確認！　地中から上がってきます！","ENG":"C.O. detected! It's coming up from the ground!","TWN":"確認到侵蝕體反應！從地下來的！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"저, 저건…….","JPN":"あ、あれは……","ENG":"Th-that's...","TWN":"那，那是……"},"stage":{"bg":"VARUNA_04_01","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"……고래잖아.\xA0","JPN":"……クジラ……か？\xA0","ENG":"...a whale.\xA0","TWN":"……鯨魚！"},"stage":{"bg":"VARUNA_04_01","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"최악이군. 처음보는 타입의 침식체다.","JPN":"なんてことだ。初めて見るタイプの侵食体だ。","ENG":"This is bad. It is a type of C.O. that I've never seen before.","TWN":"糟糕，是從沒見過的侵蝕體。"},"stage":{"bg":"VARUNA_04_01","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"놈의 전투 패턴을 파악하기 위해선…… ","JPN":"奴の戦闘パターンを確認するために…… ","ENG":"In order to figure out its attack pattern–","TWN":"首先掌握它的戰鬥模式……"},"stage":{"bg":"VARUNA_04_01","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……！"},"stage":{"bg":"VARUNA_04_01","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"클리파 허수 에너지가 급속도로 치솟고 있습니다! 이, 이대로라면……!","JPN":"クリファ虚数エネルギーが急激に上昇しています！　こ、このままでは……！","ENG":"The Qlipha Imaginary Energy is rising too quickly! I-if this continues...!","TWN":"逆卡巴拉虛數能量上升過快！這，這樣下去的話……！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_TOUCH"}}}},{"id":"L34_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"몸, 몸에서 촉수가……! 이, 이것 좀 잘라줘!","JPN":"か、身体から触手が……！　だ、誰か切ってくれ！","ENG":"T-tentacles on my body...! S-someone cut these off from me!","TWN":"從我的身體，觸手……！快幫我砍掉它！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_TOUCH"}}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"전부 쏴! 변이가 시작된 놈들은 이미 늦었다!","JPN":"撃つんだ！　変異が始まってしまった連中はもう手遅れだ！","ENG":"Shoot them all! It's too late for the ones that have started to mutate!","TWN":"開火！那些開始變異的傢伙已經沒救了！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_TOUCH"}}}},{"id":"L37_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"너희는…….","JPN":"君たちは……","ENG":"You are...?","TWN":"你們……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"좋은 아침입니다! 금일 정화도 무사히 끝나길 바라겠습니다!","JPN":"おはようございます！　本日も浄化活動から無事お戻りになることをお祈りしております！","ENG":"Good morning! I hope your purifying ends safely today!","TWN":"早安！希望今天的淨化任務也很順利！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"오늘 임무는 학회를 저지하는 것이다. 무고한 시민들이 휘말릴 수 있으니 신속히 대피시킨다.","JPN":"今日の任務は学会の阻止だ。一般市民が巻き込まれないよう、速やかに避難させるんだ。","ENG":"Today's mission is stopping the Society. Innocent citizens might get caught up, so their evacuation must be done quickly.","TWN":"今天的任務是阻止學會。可能會波及無辜的市民，所以要迅速疏散他們。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"본 기함은 블랙홀 드라이브를 탑재한 최신형 기함으로…….","JPN":"本旗艦はブラックホールドライブを搭載した最新型のものであり……","ENG":"This flagship has the state-of-the-art Black Hole Drive equipped...","TWN":"本艦為搭載黑洞引擎的最新型旗艦……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"……누구지?","JPN":"……誰だ？","ENG":"Who are you…?","TWN":"……是誰？"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"위험하다! 이쪽으로!","JPN":"危ない、こっちへ！","ENG":"You're in danger! Come this way!","TWN":"危險！跟我來！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"두 분! 괜찮으세요?","JPN":"お二人とも、大丈夫ですか？","ENG":"Hey! Are you two all right?","TWN":"你們兩個沒事吧！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"위험한 상황에서 정신을 빼고 있다니, 너답지 않군.","JPN":"危険な状況下で気を抜くとは、お前らしくないぞ。","ENG":"It's not like you to space out in such a dangerous situation.","TWN":"在危險的情況下分心，可真不像你。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"……저 침식체, 무언가 이상해.","JPN":"……あの侵食体、何か変だ。","ENG":"...That C.O., something's strange about it.","TWN":"……那個侵蝕體，有點奇怪。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"아주 잠깐, 놈과 의식이 연결된 듯한 기분이 들었다.","JPN":"一瞬、奴と意識が繋がった気がした。","ENG":"It was for a brief moment, but I felt as if my consciousness was connected to it.","TWN":"剛才有一瞬間，感覺意識和那傢伙連接在一起。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"침식체와 의식이……? 놈의 의식에서 뭘 봤지?","JPN":"侵食体と意識が……？　奴の意識から何を見た？","ENG":"Your consciousness and the C.O.'s...? What did you see in it?","TWN":"侵蝕體和意識……？那你在它的意識中看到什麼？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"기억.","JPN":"記憶。","ENG":"Memories.","TWN":"記憶。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"<color=#ff3636>처음 보는 사람들</color>의 기억을 봤다. ","JPN":"<color=#ff3636>知らない人たち</color>の記憶を見た。 ","ENG":"I saw memories of <color=#ff3636>people I've never met before</color>.","TWN":"看到<color=#ff3636>從沒見過的人</color>的記憶。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"하지만……그들이 낯설지 않아. 어째서지?","JPN":"でも……彼らを初めて見る気がしなかった。どうしてだ？","ENG":"But... They didn't feel unfamiliar. How can that be?","TWN":"但是……感覺他們並不陌生。為什麼呢？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"지금은 그런 수수께끼를 맞출 때가 아닌 것 같은데.","JPN":"今はそんな謎解きをしている場合ではないだろう。","ENG":"I don't think now's the time to solve that puzzle.","TWN":"現在可不是猜謎的時候。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"우리는 침식체를 정화한다. 가장 간단명료한 작전이지.","JPN":"俺たちは侵食体を浄化する。最もわかりやすい作戦だ。","ENG":"We are here to purify the C.O. Such a simple operation.","TWN":"我們要淨化侵蝕體，這是最簡單明瞭的作戰。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"우선 움직이자고. 저 녀석에 대한 정체는 나중에 생각해도 되잖아?","JPN":"とりあえず動こう。奴の正体については後から考えてもいいだろう？","ENG":"Let's get moving. We'll think about what it is later, all right?","TWN":"先行動吧，這些事以後再說。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"애초에 <color=#ff3636>우리 셋이서 작전을 진행해야 하는 게</color> 영 이상하단 말이지.","JPN":"そもそも、<color=#ff3636>俺たち三人で作戦遂行を行うなんて</color>全くおかしな話なんだけどな。","ENG":"It's odd that <color=#ff3636>this operation only deployed the three of us</color>.","TWN":"奇怪，為什麼<color=#ff3636>要由我們三人執行的任務</color>。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"아하하. 테라브레인이 틀린 판단을 하진 않았을 테니까요.","JPN":"あはは、テラブレインが間違った判断を下すわけはありませんよ。","ENG":"Ah hah hah. Terrabrain's never wrong, though.","TWN":"呵呵呵，特拉大腦的判斷應該不會錯吧。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"하지만 좀 이상하네요.","JPN":"でも確かに変ですね。","ENG":"Still. Something feels off.","TWN":"但確實很古怪呢。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"학회는 이 <color=#ff3636>아무도 살지 않는 도시</color>에서 무슨 짓을 하려던 것일까요?","JPN":"学会は、この<color=#ff3636>誰もいない都市</color>で何をしようとしていたのでしょうか？","ENG":"What was the Society thinking of doing <color=#ff3636>in a city where nobody lives</color>?","TWN":"學會在這座<color=#ff3636>沒人居住的城市</color>裡想做什麼呢？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"},{"id":"L34_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"도시 전체에선 클리파 허수 에너지 밀도가 계속해서 상승하고 있다.","JPN":"都市全体からクリファ虚数エネルギーの密度がどんどん上昇している。","ENG":"Qlipha Imaginary Energy density is continually rising across the city.","TWN":"整個城市的逆卡巴拉虛數能量密度持續上升。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"■■ ■■■ ■■ ■ ■■ ■■…… ■ ■■■ ■■…… ■■…… ■■!","JPN":"■■■■■■■■■■■■■、■■■■■……■■■■■■■……■■■……■■！","ENG":"■■■■ ■■■■■■ ■■■... ■■■■■■■■ ■■ ■■■■... ■■■■■■■... ■■■■■ ■■■■■■■■■■...!","TWN":"■■■■■■■■■…… ■■■■…… ■■！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"아니야. 무언가 잘못되었다.","JPN":"いや、これはおかしい。","ENG":"No. Something has gone wrong.","TWN":"不，肯定是哪裡出了問題。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"잘못되지 않았다면…… 우린 지금 무엇을 기록하고 있었단 말인가?","JPN":"そうでなければ……私たちが今記録しているものは何だ？","ENG":"If nothing went wrong... then what were we recording just now?","TWN":"如果沒有出錯的話……我們剛才到底在記錄什麼？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};